class Solution {
public:
    bool canConstruct(string s, int k) {
        if (s.length() < k) return false;
        vector<int> count(26, 0);
        for (char c : s) {
            count[c - 'a']++;
        }
        int oddCount = 0;
        for (int i = 0; i < 26; ++i) {
            if (count[i] % 2 != 0) {
                oddCount++;
            }
        }
        return oddCount <= k;
    }
};

